1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8" />
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
6	  <title>Demo User</title>
7	  <style>
8	    :root {
9	      --bg: #09090b;
10	      --surface: #131316;
11	      --text: #ededf0;
12	      --muted: #8b8b96;
13	      --accent: #5eead4;
14	      --accent-2: #a78bfa;
15	      --border: #232329;
16	    }
17	
18	    * {
19	      margin: 0;
20	      padding: 0;
21	      box-sizing: border-box;
22	    }
23	
24	    html {
25	      scroll-behavior: smooth;
26	    }
27	
28	    ::selection {
29	      background: rgba(94, 234, 212, 0.25);
30	    }
31	
32	    body {
33	      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
34	      background: var(--bg);
35	      color: var(--text);
36	      line-height: 1.6;
37	      -webkit-font-smoothing: antialiased;
38	    }
39	
40	    .container {
41	      max-width: 720px;
42	      margin: 0 auto;
43	      padding: 0 24px;
44	    }
45	
46	    /* Header / hero */
47	    header {
48	      position: relative;
49	      padding: 96px 0 64px;
50	    }
51	
52	    header::before {
53	      content: "";
54	      position: absolute;
55	      top: -160px;
56	      left: -120px;
57	      width: 480px;
58	      height: 480px;
59	      background: radial-gradient(circle, rgba(94, 234, 212, 0.08), transparent 70%);
60	      pointer-events: none;
61	    }
62	
63	    .avatar {
64	      width: 88px;
65	      height: 88px;
66	      border-radius: 50%;
67	      background: linear-gradient(135deg, var(--accent), var(--accent-2));
68	      display: flex;
69	      align-items: center;
70	      justify-content: center;
71	      font-size: 32px;
72	      font-weight: 700;
73	      color: var(--bg);
74	      margin-bottom: 24px;
75	      box-shadow: 0 0 40px rgba(94, 234, 212, 0.25);
76	    }
77	
78	    h1 {
79	      font-size: 40px;
80	      font-weight: 700;
81	      letter-spacing: -0.02em;
82	      margin-bottom: 8px;
83	    }
84	
85	    .tagline {
86	      font-size: 20px;
87	      color: var(--muted);
88	      margin-bottom: 24px;
89	    }
90	
91	    .intro {
92	      font-size: 17px;
93	      color: var(--text);
94	      max-width: 60ch;
95	    }
96	
97	    /* Sections */
98	    section {
99	      padding: 40px 0;
100	      border-top: 1px solid var(--border);
101	    }
102	
103	    h2 {
104	      font-size: 14px;
105	      font-weight: 600;
106	      text-transform: uppercase;
107	      letter-spacing: 0.08em;
108	      color: var(--muted);
109	      margin-bottom: 24px;
110	    }
111	
112	    /* Work / projects */
113	    .section-note {
114	      font-size: 16px;
115	      color: var(--muted);
116	      max-width: 60ch;
117	    }
118	
119	    .section-note a {
120	      color: var(--accent);
121	      text-decoration: none;
122	    }
123	
124	    .section-note a:hover {
125	      text-decoration: underline;
126	    }
127	
128	    /* Skills */
129	    .skills {
130	      display: grid;
131	      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
132	      gap: 16px;
133	    }
134	
135	    .skill {
136	      background: var(--surface);
137	      border: 1px solid var(--border);
138	      border-radius: 12px;
139	      padding: 20px 24px;
140	    }
141	
142	    .skill h3 {
143	      font-size: 16px;
144	      font-weight: 600;
145	      margin-bottom: 4px;
146	    }
147	
148	    .skill p {
149	      font-size: 14px;
150	      color: var(--muted);
151	    }
152	
153	    /* Contact links */
154	    .links {
155	      display: flex;
156	      flex-wrap: wrap;
157	      gap: 12px;
158	    }
159	
160	    .links a {
161	      display: inline-block;
162	      padding: 10px 18px;
163	      border: 1px solid var(--border);
164	      border-radius: 999px;
165	      color: var(--text);
166	      text-decoration: none;
167	      font-size: 15px;
168	      transition: border-color 0.15s ease, color 0.15s ease;
169	    }
170	
171	    .links a:hover {
172	      border-color: var(--accent);
173	      color: var(--accent);
174	    }
175	
176	    footer {
177	      padding: 40px 0 64px;
178	      border-top: 1px solid var(--border);
179	      color: var(--muted);
180	      font-size: 14px;
181	    }
182	
183	    @media (max-width: 480px) {
184	      header {
185	        padding: 64px 0 48px;
186	      }
187	
188	      h1 {
189	        font-size: 32px;
190	      }
191	
192	      .tagline {
193	        font-size: 18px;
194	      }
195	    }
196	  </style>
197	</head>
198	<body>
199	  <div class="container">
200	    <header>
201	      <div class="avatar">AK</div>
202	      <h1>Demo User</h1>
203	      <p class="tagline">Software engineer &amp; builder</p>
204	      <p class="intro">
205	        Hi, I'm Demo User. I build software and enjoy turning ideas into simple,
206	        well-crafted tools. This is my corner of the internet — a place for
207	        what I'm working on and how to reach me.
208	      </p>
209	    </header>
210	
211	    <section>
212	      <h2>What I'm working on</h2>
213	      <p class="section-note">
214	        I'm always building something — new projects will land here soon.
215	        In the meantime, you can find my work on
216	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>.
217	      </p>
218	    </section>
219	
220	    <section>
221	      <h2>Skills</h2>
222	      <div class="skills">
223	        <div class="skill">
224	          <h3>Web Development</h3>
225	          <p>Building responsive, accessible sites with modern HTML, CSS, and JavaScript.</p>
226	        </div>
227	        <div class="skill">
228	          <h3>Backend &amp; APIs</h3>
229	          <p>Designing and shipping reliable services, from data models to deployment.</p>
230	        </div>
231	        <div class="skill">
232	          <h3>Developer Tooling</h3>
233	          <p>Automating workflows and crafting small tools that make teams faster.</p>
234	        </div>
235	      </div>
236	    </section>
237	
238	    <section>
239	      <h2>Get in touch</h2>
240	      <div class="links">
241	        <a href="mailto:<email>">Email</a>
242	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>
243	        <a href="https://www.linkedin.com/" target="_blank" rel="noopener">LinkedIn</a>
244	      </div>
245	    </section>
246	
247	    <footer>
248	      &copy; 2026 Demo User
249	    </footer>
250	  </div>
251	</body>
252	</html>
